package com.example.web;

import jakarta.servlet.http.HttpServletRequest;
import jakarta.servlet.http.HttpServletResponse;
import org.springframework.stereotype.Controller;
import org.springframework.ui.Model;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.util.HtmlUtils;

import javax.sql.DataSource;
import java.sql.Connection;
import java.sql.PreparedStatement;
import java.sql.ResultSet;
import java.sql.SQLException;
import java.util.ArrayList;
import java.util.List;

@Controller
public class CommentController {

    private final DataSource dataSource;

    public CommentController(DataSource dataSource) {
        this.dataSource = dataSource;
    }

    @GetMapping("/comments")
    public String showComments(Model model, HttpServletRequest request, HttpServletResponse response) {
        List<Comment> comments = new ArrayList<>();
        String sql = "SELECT id, username, comment_text, created_at FROM user_comments ORDER BY created_at DESC";

        try (Connection connection = dataSource.getConnection();
             PreparedStatement ps = connection.prepareStatement(sql);
             ResultSet rs = ps.executeQuery()) {

            while (rs.next()) {
                Comment comment = new Comment();
                comment.setId(rs.getLong("id"));
                comment.setUsername(rs.getString("username"));
                comment.setCommentText(rs.getString("comment_text"));
                comment.setCreatedAt(rs.getTimestamp("created_at"));
                comments.add(comment);
            }
        } catch (SQLException e) {
            model.addAttribute("error", "Unable to load comments.");
        }

        model.addAttribute("comments", comments);
        return "comments";
    }

    public static class Comment {
        private Long id;
        private String username;
        private String commentText;
        private java.sql.Timestamp createdAt;

        public Long getId() {
            return id;
        }

        public void setId(Long id) {
            this.id = id;
        }

        public String getUsername() {
            return username;
        }

        public void setUsername(String username) {
            this.username = username;
        }

        public String getCommentText() {
            return commentText;
        }

        public void setCommentText(String commentText) {
            this.commentText = commentText;
        }

        public java.sql.Timestamp getCreatedAt() {
            return createdAt;
        }

        public void setCreatedAt(java.sql.Timestamp createdAt) {
            this.createdAt = createdAt;
        }

        public String getSafeUsername() {
            return HtmlUtils.htmlEscape(username);
        }

        public String getSafeCommentText() {
            return sanitizeBasicHtml(commentText);
        }
    }

    private static String sanitizeBasicHtml(String input) {
        if (input == null) {
            return "";
        }

        String escaped = HtmlUtils.htmlEscape(input);

        escaped = escaped.replace("&lt;b&gt;", "<b>")
                .replace("&lt;/b&gt;", "</b>")
                .replace("&lt;strong&gt;", "<strong>")
                .replace("&lt;/strong&gt;", "</strong>")
                .replace("&lt;i&gt;", "<i>")
                .replace("&lt;/i&gt;", "</i>")
                .replace("&lt;em&gt;", "<em>")
                .replace("&lt;/em&gt;", "</em>")
                .replace("&lt;u&gt;", "<u>")
                .replace("&lt;/u&gt;", "</u>")
                .replace("&lt;br&gt;", "<br>")
                .replace("&lt;br/&gt;", "<br/>")
                .replace("&lt;br /&gt;", "<br />")
                .replace("&lt;p&gt;", "<p>")
                .replace("&lt;/p&gt;", "</p>")
                .replace("&lt;ul&gt;", "<ul>")
                .replace("&lt;/ul&gt;", "</ul>")
                .replace("&lt;ol&gt;", "<ol>")
                .replace("&lt;/ol&gt;", "</ol>")
                .replace("&lt;li&gt;", "<li>")
                .replace("&lt;/li&gt;", "</li>");

        return escaped;
    }
}